export default (role) => {
    return new Promise((resolve, reject) => {
        window.fetch("https://thebastionbot.herokuapp.com/members/" + role, {
            headers: {
                "UserAgent": "The Bastion Bot Website (https://bastionbot.org)",
            },
        })
        .then(res => res.json())
        .then(data => {
            console.log(data);
            resolve(data);
        })
        .catch(e => reject(e));
    });
};
