import React from "react";

import Layout from "../layouts/default";
import PageHeader from "../components/PageHeader";
import PageContent from "../components/Content";
import Loader from "../components/Loader";
import Card from "../components/Card";
import fetchMembers from "../utils/fetchMembers";

let cachedMembers = {};

export default class Members extends React.Component {
    constructor(props) {
        super(props);

        this.state = {
            members: {},
        };
    }

    componentDidMount() {
        if (Object.values(cachedMembers).length) {
            this.setState({ members: cachedMembers });
        } else {
            fetchMembers("moderators").then(fetchedModerators => {
                fetchedModerators.forEach(m => {
                    cachedMembers[m.id] = {
                        tag: m.username + "#" + m.discriminator,
                        avatar: m.avatar,
                        roles: [ "Moderator" ],
                    };
                });

                fetchMembers("support").then(fetchedSupportStaff => {
                    fetchedSupportStaff.forEach(m => {
                        if (m.id in cachedMembers) {
                            cachedMembers[m.id].roles.push("Support");
                        } else {
                            cachedMembers[m.id] = {
                                tag: m.username + "#" + m.discriminator,
                                avatar: m.avatar,
                                roles: [ "Support" ],
                            };
                        }
                    });

                    this.setState({ members: cachedMembers });
                }).catch(console.error);
            }).catch(console.error);
        }
    }

    render () {
        return (
            <Layout
                title="Members"
                description="These are the cool and amazing members of Bastion HQ Discord Server. These are the people who keep the Discord server running in equilibrium."
                image=""
            >
                <PageHeader />

                <PageContent>
                    <div css={{
                        textAlign: "center",
                        marginBottom: 50,
                    }}>
                        <h1>HQ Members</h1>
                        <p>
                            The cool and amazing members of Bastion HQ Discord Server. These
                            are the people who keep the Discord server running in equilibrium.
                        </p>
                        <p>
                            If you also want to be a part of this amazing team and help us
                            keep the Discord server running, contact us in Bastion HQ.
                        </p>
                    </div>

                    <div css={{
                        display: "flex",
                        flexWrap: "wrap",
                        justifyContent: "center",
                    }}>
                        {
                            Object.values(this.state.members).length
                            ? Object.values(this.state.members).map((user, i) => (
                                <Card
                                    key={ i }
                                    tagline={ user.tag }
                                    description={ user.roles.join(" / ") }
                                    // image={ user.avatar }
                                    maxWidth={ 300 }
                                    center={ true }
                                    middle={ true }
                                    dark={ true }
                                />
                            ))
                            : <Loader />
                        }
                    </div>
                </PageContent>
            </Layout>
        );
    }
};
